import React from 'react';
import Logo from "./logo.svg";
import Box from "@mui/material/Box";

const ErgLogo = () => {

    return (
        <Box
            component="img"
            sx={{
                position: 'absolute',
                top: '50%',
                left: '0%',
                transform: 'translate(10%, -50%)',
                height: 64,
            }}

            alt="ERG logo"
            src={Logo}
        />
    )
};

export default ErgLogo;
